342	    'PI', '地址', '下单信号', '报价', '样品', '运费',
343	    '最近我方消息', '最近客户消息', '分类理由', '行动建议', '沉默风险', '手动调整'
344	  ];
345	
346	  const headerRow = ws.addRow(headers);
347	  headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
348	  headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
349	  headerRow.alignment = { vertical: 'middle', horizontal: 'center' };
350	
351	  // 颜色定义
352	  const tierColors = {
353	    p0: { argb: 'FFFFC7CE' }, // 红色
354	    p1: { argb: 'FFFFEB9C' }, // 黄色
355	    p2: { argb: 'FFC6EFCE' }, // 绿色
356	    p3: { argb: 'FFBDD7EE' }, // 蓝色
357	    p4: { argb: 'FFD9D9D9' }  // 灰色
358	  };
359	  const silenceColors = {
360	    danger: { argb: 'FFFF4444' },
361	    warning: { argb: 'FFFFAA00' }
362	  };
363	
364	  for (const c of customers) {
365	    const stage = determineStage(c);
366	    const silence = checkSilence(c, rules);
367	
368	    const row = ws.addRow([
369	      c.score.toFixed(0),
370	      `${c.tier.toUpperCase()} - ${c.tierLabel}`,
371	      c.name || '(未知)',
372	      c.country || '',
373	      stage.label,
374	      c.daysAgo ?? '',
375	      c.msgCount ?? '',
376	      c.customerMsgs ?? '',
377	      c.ourMsgs ?? '',
378	      c.cRatio != null ? `${c.cRatio}%` : '',
379	      c.hasPI ? '✓' : '',
