382	      c.hasPrice ? '✓' : '',
383	      c.hasSample ? '✓' : '',
384	      c.hasFreight ? '✓' : '',
385	      (c.latestOurMsg || '').substring(0, 60),
386	      (c.latestCustMsg || '').substring(0, 60),
387	      c.tierReason || '',
388	      stage.action,
389	      silence === 'danger' ? '严重' : silence === 'warning' ? '注意' : '',
390	      c.tierReason === '（手动覆盖）' ? '已覆盖' : ''
391	    ]);
392	
393	    // 行着色
394	    const bg = tierColors[c.tier] || tierColors.p4;
395	    row.eachCell((cell, colNum) => {
396	      cell.fill = { type: 'pattern', pattern: 'solid', fgColor: bg };
397	      cell.alignment = { vertical: 'middle', wrapText: true };
398	    });
399	
400	    // 沉默风险着色
401	    if (silence === 'danger' || silence === 'warning') {
402	      const silenceCell = row.getCell(21);
403	      silenceCell.font = { bold: true, color: { argb: silence === 'danger' ? 'FFFF0000' : 'FFFF8800' } };
404	    }
405	  }
406	
